-- Create Database
CREATE DATABASE IF NOT EXISTS eobra_db CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE eobra_db;

-- Users Table
CREATE TABLE IF NOT EXISTS users (
    id INT AUTO_INCREMENT PRIMARY KEY,
    firebase_uid VARCHAR(255) NOT NULL UNIQUE,
    first_name VARCHAR(100) NOT NULL,
    last_name VARCHAR(100) NOT NULL,
    email VARCHAR(255),
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Chapters Table
CREATE TABLE IF NOT EXISTS chapters (
    id INT AUTO_INCREMENT PRIMARY KEY,
    chapter_number INT NOT NULL,
    title VARCHAR(255) NOT NULL,
    content TEXT NOT NULL,
    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

-- Glossary Table
CREATE TABLE IF NOT EXISTS glossary (
    id INT AUTO_INCREMENT PRIMARY KEY,
    word VARCHAR(100) NOT NULL UNIQUE,
    definition TEXT NOT NULL,
    modern_context TEXT
);

-- Quizzes Table
CREATE TABLE IF NOT EXISTS quizzes (
    id INT AUTO_INCREMENT PRIMARY KEY,
    chapter_id INT NOT NULL,
    title VARCHAR(255) NOT NULL,
    FOREIGN KEY (chapter_id) REFERENCES chapters(id) ON DELETE CASCADE
);

-- Questions Table
CREATE TABLE IF NOT EXISTS questions (
    id INT AUTO_INCREMENT PRIMARY KEY,
    quiz_id INT NOT NULL,
    question_text TEXT NOT NULL,
    option_a VARCHAR(255) NOT NULL,
    option_b VARCHAR(255) NOT NULL,
    option_c VARCHAR(255) NOT NULL,
    option_d VARCHAR(255) NOT NULL,
    correct_answer CHAR(1) NOT NULL, -- A, B, C, or D
    FOREIGN KEY (quiz_id) REFERENCES quizzes(id) ON DELETE CASCADE
);

-- Insert Kabanata 1
INSERT INTO chapters (chapter_number, title, content) VALUES 
(1, 'Isang Pagtitipon', 'Magtatapos ang Oktubre nang magpahapunan si Don Santiago de los Santos, kilala sa palayaw na Kapitan Tiago, at kahit ipinahayag lamang sa hapong iyon, na hindi niya ugali, naging paksa ito ng lahat ng usapan sa Binondo, sa ibang karatig-pook, at hanggang sa Intramuros. Tinitingala noon si Kapitan Tiago bilang isang napakagalanteng ginoo, at kasabihan na ang kaniyang bahay, tulad ng kaniyang bayan, ay hindi nagsasara ng pinto kanino man, huwag lamang may komersiyo o mga kaisipang bago at pangahas.\n\nTila nakagugulat na koryenteng sumagitsit ang balita sa daigdig ng mga limatik, mga langaw, at matatakaw na nilalang ng Diyos mula sa Kaniyang walang-hanggang kabutihan, at buong giliw na pinarami sa Maynila. May mga nag-apuhap ng biton ukol sa kanilang botas; ang iba, ng mga butones at kurbata; ngunit pawang nag-isip kung paano buong kapalagayang babatiin ang may bahay upang mapaniwala na matagal nang kakilala, dili kaya’y ng mga dahilan, kung kailangan, sapagkat hindi nakadalo nang higit na maaga.\n\nIdinaos ang hapunan sa isang bahay sa Kalye Anloague, at sapagkat hindi na namin maalaala ang numero, ilalarawan namin sa paraang makikilala pa kung hindi pa ito nawawasak ng mga lindol. Hindi kami naniniwala na ipagigiba ito ng may-ari, sapagkat karaniwang ipinababahala ang ganitong gawain sa Diyos o sa Kalikasan, na mayhawak din sa maraming ipinakontratang gawain ng aming Pamahalaan.\n\nMay kalakihan ang bahay na ito, may estilong kahawig ng karamihan sa bayang ito, nakatayo sa dakong tabi ng isang sanga ng Pasig na tinatawag ng ilan na wawa ng Binondo at gumaganap, tulad ng lahat ng ilog sa Maynila, bilang paliguan, basurahan, labahan, pangisdaan, daluyan ng sasakyan at komunikasyon, at hanggang salukan ng tubig inumin kung ikagiginhawa ito ng Tsinong agwador. Dapat pansinin na sa maunlad na bahaging ito karatig ng Maynila, na magulo ang trapiko at nakahihilo ang salimbayan, sa agwat na halos isang kilometro, naipagmamalaki lamang ang isang tulay na kahoy na sira ang isang panig sa loob ng anim na buwan at hindi madaanan ang kabila sa nalalabing kalahating taon. Sa ganitong kapalaran, sinasamantala ng mga kabayo ang hindi natitinag na kalagayan kapag kainitan ng panahon upang sumisid buhat sa tulay, na ikinagugulantang ng mga walang kamalay-malay na pasahero dahil naiidlip sa loob ng karwahe o nagmumuni tungkol sa mga kaunlaran ng dantaon.\n\nMay kababaan at hindi gaanong tuwid ang mga gilid ng bahay na aming tinutukoy. Marahil dahil mahina ang mata ng arkitektong nagtayo nito o dulot ng mga lindol at bagyo. Walang makapagsasabi nang tiyak. May malapad na hagdang berde ang barandilya’t may latag na pira-pirasong alpombra mula sa zaguan o pasukan, baldosa hanggang itaas at nahahanayan ng mga masetas at mga paso ng bulaklak na nakapatong sa mga pedestal na porselanang Tsino, sari-sari ang kulay, at kagila-gilalas ang mga dibuho.\n\nSapagkat walang mga bantay ni mga utusan na hihingi o mag-uusisa sa imbitasyon, aakyat tayo: O, ikaw na bumabasa sa akin, kaibigan ka man o kaaway! Kung maakit ka ng armonya ng orkestra, ng ilaw, o ng makahulugang kalansingan ng pinggan at kubyertos, at nais mong masaksihan kung paano magdaos ng mga pagtitipon doon sa Perlas ng Silangan. Ikatutuwa ko, bukod sa ikagiginhawa ko na huwag nang ilarawan ang bahay, ngunit napakahalaga nito. Sapagkat sa kalahatan, tayong mga mortal ay katulad ng mga pawikan: hinahalagahan tayo at inuuri sang-ayon sa ating mga talukab. Dahil dito at sa iba pang katangian, tila mga pawikan din ang mga tao sa Filipinas.\n\nPagpanhik natin, agad tayong bubungad sa isang maluwang na kabahayan, tinatawag doon na caida, at hindi ko alam kung bakit, na sa gabing ito’y nagsisilbing komedor at salon para sa orkestra. Nasa gitna ang isang mahabang mesa, labis ang gayak at napakarangya, at nagkikindat wari ng matatamis na pangako sa matakaw habang nagbabanta sa mayuming binibini, sa matapat na dalaga, tungkol sa dalawang mapanganib na oras sa piling ng mga di-kakilala, na kaibang-kaiba ang katangian ng wika’t paraan ng pakikipag-usap. Kasalungat ng mga nabanggit na paghahandang makalupa ang mga kuwadrong nakatanghal sa mga dingding at naglalarawan ng mga paksang panrelihiyon, gaya ng El Purgatorio (Purgatoryo), El Infierno (Impiyerno), El Juicio Final (Huling Paghuhukom), La Muerte del Justo, (Kamatayan ng Makatarungan), La del Pecador (Kamatayan ng Makasalanan), at sa wakas, nakakulong sa marikit at maringal na kuwadrong estilong Renacimiento na inukit marahil ni Arevalo, isang kakaibang linso na malaki ang sukat at nagpapakita ng dalawang matandang babae. Nakasulat sa ibaba: Ntra. Sra. de la Paz y Buenviaje, que se venera en Antipolo, bajo el aspecto de una mendiga visita en su enfermedad a la piadoso y celebre capitana Ines. (Ang Mahal Nating Poon ng Kapayapaan at Mabuting Paglalakbay na sinasamba sa Antipolo. Dumalaw nang nakadamit pulubi sa maysakit na mahabagin at bantog na si Kapitana Ines.) Bagaman walang gaanong panlasa o sining itong ipinamamalas, nagtataglay naman ito ng labis na realismo. Tila isang bangkay nang nabubulok ang maysakit dahil sa pahid na manilaw-nilaw at asul sa kaniyang mukha. Mga gamit sa matagal na pagkaratay ang mga baso at ibang bagay, at buong tiyagang iginuhit ang mga ito kaya makikita kahit ang mga laman nito. Kapag pinagmuni ang mga kuwadrong ito na gumaganyak sa ganang kumain at pumupukaw sa mga ideang pambukid, aakalain ng ilan na kilalang-kilala ng matalinong may-ari ng bahay ang pagkatao ng karamihan sa dudulog sa mesa kaya’t upang ikubli nang bahagya ang laman ng kaniyang isip ay nagpalamuti ng maririkit na lamparang Tsino, mga haulang walang ibon, mga bolang kristal na may asoge at kulay pula, berde’t asul, mga lanta nang halamang pambitin, mga pinatuyong botete na hinipan para lumobo, atbp. Ang panig na katatanawan ng ilog ay ganap na natabingan ng mga kaakit-akit na arkong kahoy, may mala-Tsino at may mala-Europeo, at masisilip sa isang asotea ang mga balag ng baging at ang gloryeta na bahagyang naiilawan ng maliliit na parol na papel at sari-sari ang kulay.\n\nNaroon sa sala ang mga kakain, sa gitna ng malalaking salamin at makikinang na aranya. Naroon din, sa ibabaw ng isang tarimang kahoy na pino ang isang napakaringal at napakamahal na piyanong de-kola, at tila higit na mamahalin ngayong gabi sapagkat walang tumutugtog. Naroon ang isang malaking larawan sa oleo ng isang makisig na ginoo, nakafrak, unat na unat, tuwid na tuwid, walang-pingas tulad ng bastong may borlas at pigil ng kaniyang mga panatag na daliring nababalot sa singsing. Waring ibig sabihin ng nakalarawan: “Ehem! Tingnan kung gaano ako kagilas at kung gaano ako kagalang-galang!”\nElegante ang mga muwebles, bagama’t hindi marahil mabuting upuan at masamâ sa katawan. Maaaring higit na sinunod ng may-ari ng bahay ang sariling luho kaysa isaalang-alang ang kalusugan ng kaniyang mga panauhin. Wari pang sinasabihan sila na: “Nakatatakot ang disenteriya, ngunit nakaupo naman kayo sa silyang buhat pa sa Europa! Hindi kayo nakauupo sa ganiyan araw-araw!”\nHalos mapunô sa tao ang sala. Magkabukod ang mga lalaki at mga babae, tulad sa mga simbahang Katoliko at sa mga sinagoga. Ilang binibining Filipina at Espanyola ang kababaihan; napapanganga sila upang pigilin ang paghihikab, at dagling tinatakpan ng kanilang abaniko ang kanilang bibig. Halos ayaw nilang umimik. Ang mga pagsisikap makipag-usap ay nagwawakas sa mga ungol at kataga, katulad ng mga ingit na naririnig sa loob ng bahay kung gabi—ang ingit ng mga daga’t butiki. Bunga kaya ng mga larawan ng birhen at santang nakasabit sa paligid ang nag-aatas sa kanilang panatilihin ang pananahimik at maupong kabanal-banalan? O sadyang natatangi ang kababaihan sa bayang ito?\nNag-iisang tumatanggap sa mga ginang ang matanda nang pinsang babae ni Kapitan Tiago. Magiliw ang kaniyang anyo bagama’t may kasamâan ang kaniyang pangangastila. Ipinahahayag niya ang pag-aasikaso’t kagandahang-asal sa pamamagitan ng pag-aalok ng isang bandeha ng tabako’t buyo sa mga Espanyola at ng pagpapahalik ng kamay sa mga Filipina, sa paraang gayang-gaya ang mga fraile.\n\nNang lumaon, nayamot din ang kawawang matanda at, sinamantala ang ingay ng nabasag na pinggan, matuling lumabas habang bumubulong: “Susmaryosep! Makikita ninyo, mga tanga!”\nAt hindi na muling lumitaw.\n\nSa kabilang dako, umiingay na sa panig ng kalalakihan. Sa isang sulok, masiglang nag-uusap ang ilang kadete, ngunit sa mahinang tinig, tumitingin paminsan-minsan sa paligid at manaka-nakang itinuturo ang ilang tao sa sala, saka palihim na nagtatawanan. May dalawang estranghero naman, puting-puti ang suot, nakapalikod-kamay at walang-imikan, na malalaki ang hakbang na pabalik-balik sa magkabilang dulo ng sala, katulad ng mga nababagot na pasahero sa kubyerta ng bapor. Nagbubuhat ang lahat ng interes at sigla sa isang pangkat na binubuo ng dalawang alagad ng Simbahan, dalawang mamamayan, at isang militar na nangakaupong magkakaharap sa isang mesita na may mga botelya ng alak at biskotsong Ingles.\n\nIsang tenyente ang militar, matangkad, at matigas ang mukha. Tila isang Duke de Alba na naiwanan sa listahan ng Guwardiya Sibil, matipid siyang magsalita ngunit madiin at maikli. Ang isa sa mga fraile ay isang batà pang Dominiko, makisig, malinis, at makinang gaya ng kaniyang ginintuang salamin sa mata ngunit maagang nagmukhang matanda. Siya ang kura ng Binondo at naging guro nitong mga nagdaang taon sa San Juan de Letran. Tanyag siyang napakahusay sa pakikipagtalo kaya noong panahong iyon na nangangahas pang makipagtagisan ng talino ang mga anak ni Guzman laban sa mga sekular, hindi siya nalito ni tinalo ng magaling sa pangangatwirang si B. de Luna. Dahil sa matalinong paglilinaw ni Fray Sibyla, naihalintulad siya sa isang mangingisda na humuhuli ng palos sa pamamagitan ng isang pansilo. Matipid ding mangusap ang Dominiko at tila tinitimbang mabuti ang kaniyang mga pangungusap.\n\nKaiba sa kaniya, madaldal at mahilig kumumpas ang ikalawa na isang Pransiskano. Kahit nag-uuban na ang kaniyang buhok, waring matibay pa ang kaniyang pangangatawan. Dahil sa katamtaman niyang anyo, nakahihindik na tingin, malalapad na panga, at matipunong pangangatawan, animo isang nakabalatkayo siyang maharlikang Romano, at wala sa loob na maaalala mo ang isa sa tatlong monghe na binanggit ni Heine sa kaniyang Mga Diyoses sa Destiyero, na kapag equinox ng Setyembre, doon sa Tyrol sa hatinggabi’y nagdaraang nakabangka at nag-iiwan sa kamay ng bawat kawawang bangkero ng isang salaping pilak, na sinlamig ng yelo, at ikinasisindak nito. Gayunman, hindi tulad nilang mahiwaga si Fray Damaso. Masayahin siya at kung magaspang mang magsalita, gaya ng isang taong walang pangingimi ang dila at nag-aakalang banal at wala nang bubuti pa sa bawat ipahayag niya, pinapawi ng kaniyang masaya at matapat na tawa ang anumang masamâng hinala, at mapipilitan tuloy ang sinuman na ipagpatawad ang kaniyang pagtatanghal, sa gitna ng sala, ng mga paang walang medyas at mga binting mabalahibo na maaaring ikabuhay ng isang Mendieta sa mga perya sa Quiapo.\n\nAng una sa dalawang mamamayan ay pandak na lalaki, maitim ang balbas, at kapansin-pansin dahil sa ilong na batay sa kaniyang laki’y hindi bagay sa kaniya. Isang binatang mamula-mula ang buhok ang ikalawa at waring kararating pa lamang sa bansa. Sa kaniya masiglang nakipag-usap ang Pransiskano.\n\n“Makikita mo,” sabi nito, “ilang buwan lang sa bansang ito at maniniwala ka sa sabi ko. Iba ang mamahala roon sa Madrid kaysa tumigil dito sa Filipinas.”\n“Pero...”\n“Ako, por ehemplo,” patuloy ni Fray Damaso na pinalakas ang tinig upang hindi makapagsalita ang kausap, “ako na dalawampu’t tatlong taon nang kumakain ng saging at kanin, ako ang puwedeng magsalita nang may autoridad tungkol sa bagay na iyan. Huwag ninyo akong gamitan ng mga teorya at retorika, kilala ko ang Indio. Dapat malaman na mula nang dumating ako rito’y nadestino na ako sa isang bayan, na totoong maliit ngunit nakaukol ang buhay ng lahat sa agrikultura. Kahit hindi ko pa naiintindihang mabuti ang Tagalog, kinukumpisal ko na ang mga babae, at nagkakaintindihan kami, at nagustuhan nila ako kaya makaraan ang tres anyos, nang ilipat ako sa isang malaking bayan, na nabakante dahil namatay ang kurang Indio, nag-iyakan ang lahat ng babae, binigyan ako ng napakaraming handog, inihatid ako ng banda ng musiko...”\n“Pero ipinakikita nga niyan...”\n“Hintay ka, hintay! Huwag kang pakabilis! Iyong kahalili ko, tumigil lang doon sa napaikling panahon, pero nang umalis ay mas maraming naghatid, mas maraming luha, mas malaking banda gayong mas mabigat siya magparusa at halos dinoble ang mga deretsos ng parokya.”\n“Pero ipahintulot ninyo sa akin...”\n“Dagdag pa, beinte anyos ako tumigil sa bayan ng San Diego at may ilang buwan ko pa lamang...iniwan.” Waring sumama ang loob sa bahaging ito. “Ang beinte anyos, hindi maikakait sa akin ninuman, ay supisyente para makilala ang isang bayan. May seis mil kaluluwa ang San Diego, at kilala ko sila lahat na para bang ako ang nagsilang at nagpasuso. Alam ko kung alin ang masamâng hilig ni ganito, kung ano ang sanhi ng paghihikahos ni ganoon, kung sino ang umiibig sa dalagang iyon, kung ano ang ikinasira ni ganito, at kung sino, kung sino ang tunay na ama ng batà, atbp., dahil sa akin nagkukumpisal ang lahat. Nag-iingat silang huwag magkulang sa kanilang tungkulin. Si Santiago, ang may-ari ng bahay na ito, ang magsasabi sa iyo. Marami siyang lupain doon at doon kami naging magkaibigan. Makikita rin ninyo kung ano ang Indio. Nang umalis ako, walang naghatid sa akin kundi ilang matandang babae at ilang hermanos terceros, gayong tumigil ako roon nang beinte anyos!”\n“Pero hindi ko makita kung ano ang kinalaman niyan sa pagpapatigil ng monopolyo sa tabako!” pakli ng mapula ang buhok na sinamantala ang pag-tungga ng Pransiskano sa kopita ng jerez.\n\nDahil sa pagkagitla, muntik nang mabitiwan ni Fray Damaso ang kopita. Saglit niyang tinitigan ang binata mulang ulo hanggang paa at, “Ano? Ano?” bulalas nito pagkatapos na takang-taka. “Diyata’t hindi ninyo makita iyang maliwanag pa kaysa sinag ng araw? Hindi ba ninyo nakikita, anak ka ng Diyos, na malinaw na pruweba ang lahat na ito na hindi rasyonal ang mga repormang ginagawa ng mga ministro?”\nNgayon, si Mapulang Buhok naman ang nagtaka, halos tumikwas ang kilay ng tenyente, tumatango-tango ang lalaking pandak sa paraang mahirap tantuin kung sumasang-ayon o hindi kay Fray Damaso. Walang magawa ang Dominiko kundi talikuran silang lahat.\n\n“Naniniwala ba kayo...” seryong-seryong naitanong sa wakas ng binata at tigib sa pag-uusisang tumitig sa fraile.\n\n“Kung naniniwala ako? Gaya ng paniniwala ko sa Ebanghelyo! Napakatamad ng Indio!”\n“A, ipagpatawad ninyo ang paggambala ko sa inyo,” wika ng binata na hininaan ang tinig at bahagyang inilapit ang kaniyang silya. “Bumigkas kayo ng pahayag na pumukaw sa aking kalooban. Tunay nga bang likás ang katamaran sa mga katutubo o ang nangyayari, gaya ng sabi ng isang banyagang manlalakbay, ginagamit lamang nating katwiran ang katamarang iyon para pagtakpan ang sa atin, ang ating pagkukulang at ang ating sistemang kolonyal? Binanggit niya ang ibang mga kolonya na may mga mamamayang katulad ng mga tagarito ang lipi...”\n“Ba! Mga inggit lang iyan! Itanong mo kay Senyor Laruja na nakakikilala rin sa bayang ito. Itanong ninyo kung may kapantay sa kamangmangan at katamaran ang Indio!”\n“Totoo,” pakli ng lalaking pandak na siyang tinukoy, “saanmang parte ng mundo, hindi kayo makakikita ng mas tamad pa sa Indio, saanmang parte ng mundo!”\n“Kahit ng mas mabisyo, at mas inggrato!”\n“Kahit ng mas mal-edukado!”\nNababalisang luminga-linga ang binatang mapula ang buhok. “Mga ginoo,” ang wikang mahinay, “sa akala ko’y nasa bahay tayo ng isang Indio. Iyong mga binibini...”\n“Ba! Huwag kayong mag-alala! Hindi ikinokonsidera ni Santiago na isang Indio siya, at saka, wala siya at...kahit narito siya! Mga katontohan iyan ng mga bagong dating. Bayaan mong makaraan ang ilang buwan at magbabago ang palagay mo kapag nakadalo na sa maraming pista at bailuhan, kapag nakatulog na sa mga katre, at kapag nakakain na ng maraming tinola.”\n“Iyan bang tinatawag ninyong tinola ang bunga ng isang uri ng loto na nagdudulot sa mga tao...para maging...malilimutin?”\n“Hindi loto ni loterya!” sagot na tumatawa ni Fray Damaso. “Lumilitaw tuloy ang inyong katangahan. Ang tinola ay gulay na manok at upo. Gaano katagal na ba kayo dumating?”\n“Apat na araw na,” naiinis na tugon ng binata.\n\n“Pumarito ba ikaw para maging empleado?”\n“Hindi senyor. Naparito ako sa sariling gugol upang makilala ang bayang ito.”\n“Aba, pambihira kang ibon!” bulalas ni Fray Damaso at minasdan siyang takang-taka. “Naparito sa sariling gugol at para sa bagay na walang kabuluhan! Napakalaking kababalaghan! Napakarami nang libro...kahit makitid ang noo mo... marami nang sumulat diyan ng makakapal na libro! Kahit makitid ang noo mo...”\n“Sinabi ng Inyong Reberensiya, Padre Damaso,” magaspang na sabad ng Dominiko sa usapan, “na dalawampung taon kayo sa bayan ng San Diego at iniwan ninyo ito...hindi ba nasiyahan ang Inyong Reberensiya sa bayan?”\nSa tanong na ito, na ipinahayag sa paraang malumanay at waring walang-bahala, biglang napawi ang tuwa ni Fray Damaso at tumigil sa pagtawa.\n\n“Hindi!” tuyot niyang ungol at pabagsak na sumandal sa silyon.\n\nNagpatuloy ang Dominiko sa himig na higit pang mapagwalang-bahala. “Talagang lubhang masakit iwan ang isang bayang tinigilan ng dalawampung taon at nakilala na tulad ng damit na suot. Ako, kahit paano, nalungkot din ako pag-alis sa Camiling, at ilang buwan lamang ako roon. Pero iniutos iyon ng mga nakatataas para sa kabutihan ng Komunidad...at para sa kabutihan ko rin.”\nSa unang pagkakataon sa gabing iyon nagmukhang balisang-balisa si Fray Damaso. Bigla niyang binayo ang katangang-kamay ng silyon at humihingal na bumulalas, “May Relihiyon o wala. Sa tahas na sabi, may laya ang mga kura o wala! Napapahamak ang bayan, napahamak na!”\nAt muling bumayo.\n\nNagulat ang lahat sa sala at napatingin sa pangkat. Bahagyang tumingala ang Dominiko upang tingnan ang Pransiskano sa ilalim ng kaniyang salamin. Huminto sandali ang dalawang dayuhang palakad-lakad, nagkatinginan, nagngitian, at ipinagpatuloy agad ang paglakad-lakad.\n\n“Sumama ang loob dahil hindi ninyo tinawag ng Inyong Reberensiya!” bulong ni Laruja sa binatang mapula ang buhok.\n\n“Ano ang ibig sabihin ng Inyong Reberensiya? Ano ang nangyayari sa inyo?” tanong ng Dominiko at ng tenyente sa magkaibang himig.\n\n“Kaya dumarating ang napakaraming kalamidad! Tinatangkilik ng mga nasa gobyerno ang mga erehe laban sa mga ministro ng Diyos!” patuloy ng Pransiskano na itinaas ang malalaking kamao.\n\n“Ano ang ibig ninyong sabihin?” tanong muli ng kunot-noong tenyente na bahagyang napatayo.\n\n“Ano ang ibig kong sabihin?” ulit ni Fray Damaso na lalong inilakas ang boses at hinarap ang tenyente. “Sinasabi ko ang ibig kong sabihin! Ako, ibig kong sabihin na kapag ipinaalis ng isang kura sa kaniyang sementeryo ang bangkay ng isang erehe ay wala, kahit ang hari’y wala karapatang makialam at lalo nang wala karapatang magparusa. Gasino pa ang isang heneralito, si Heneralito Kalamidad...”\n“Padre, ang Kaniyang Kamahalan ang Vice Real Patrono!” sigaw ng militar at tumindig.\n\n“Ano bang kamahalan, ano bang Vice Real Patrono!” pakli ng Pransiskanong tumindig din. “Kung nangyari ito noon, kinaladkad na sana siya pababa ng hagdan gaya ng ginawa minsan ng mga Korporasyon sa lapastangang si Gobernador Bustamante. Yaon ang tunay na panahon ng pananampalataya!”\n“Binabalaan ko kayo na hindi ko ipahihintulot…Kinakatawan ang Kaniyang Kataas-taasan ng Kaniyang Kamahal-mahalan, ang Hari!”\n“Ano bang hari-hari! Para sa amin, walang ibang hari kundi ang lehitimo...”\n“Tigil!” sigaw na nagbabanta ng tenyente at waring nag-uutos sa kaniyang mga sundalo. “Bawiin ninyo ang lahat ng inyong sinabi o bukas na bukas din ay ipagbibigay-alam ko sa Kaniyang Kataas-taasan.”\n“Sulong kayo, ngayon din, sulong kayo!” pauyam na sagot ni Fray Damaso at lumapit pa sa kausap nang kuyom ang mga kamao. “Akala ba ninyo, dahil nakaabito ako’y kulang ako...? Sulong kayo, ipahihiram ko pa sa inyo ang karwahe ko!”\nNaging katawa-tawa ang usapan, salamat at namagitan ang Dominiko.\n\n“Mga ginoo!” wika sa tonong makapangyarihan at sa tinig na pinalalaki, na siyang tatak ng mga fraile. “Huwag ninyong gusutin ang ayos ng bagay-bagay at hanapan ng ikagagalit ang wala. Dapat nating pagbukurin sa mga salita ni Fray Damaso ang pangungusap ng isang tao at ang pangungusap ng isang pari. Iyong sa huli, samakatwid per se ay hindi kailanman makasasakit dahil nagbubuhat sa ganap na katotohanan. Iyong sa tao’y dapat lagyan pa ng isang pagbubukod: ang sinasabi ab irato, ang sinasabi ex ore ngunit hindi in corde, at ang sinasabi in corde. Itong panghuli lamang ang maaaring makasakit at alinsunod pa sa mga pangyayari: kung in mente na’t sadyang may motibo dili kaya’y naganap lamang per accidens dahil sa sigabo ng pagtatalo, kung may...”\n“Puwes, sa aking tingin, por accidens y por mi, batid ko ang mga motibo, Padre Sibyla!” putol ng militar dahil napupunang gumugulo na ang paglilinaw at nangangambang kung magpatuloy ito ay baka siya pa ang lumabas na may kasalanan. “Batid ko ang mga motibo at pakilinaw nga ng Inyong Reberensiya kung ano sa mga iyon. Noong wala si Padre Damaso sa San Diego, ipinalibing ng koadyutor ang bangkay ng isang napakarangal na ginoo...opo, napakarangal niya, maraming ulit ko siyang nakadaupang-palad at naging panauhin ako sa kaniyang tahanan. Totoo nga, hindi siya nangumpisal kahit kailan, ngunit ano kung hindi? Hindi rin ako nangungumpisal. Ngunit ang sabihing nagpakamatay siya ay isang kasinungalingan, isang paninirang-puri. Ang isang taong tulad niya, na may isang anak na pinagbubuhusan ng pagmamahal at pag-asa, isang tao na may sampalataya sa Diyos, na nakauunawa ng mga tungkulin niya sa lipunan, isang taong marangal at makatarungan, ay hindi magpapakamatay. Ito ang sinasabi ko, at hindi ko na sasabihin ang iba ko pang iniisip, at dapat ninyong ipagpasalamat sa akin Inyong Reberensiya.”\nAt nagpatuloy habang tumitalikod sa Pransiskano:\n“Aba, ang kurang ito, nang bumalik sa bayang iyon, pagkatapos bugbugin ang pobreng koadyutor, ipinahukay ang bangkay at ipinalabas ng sementeryo para ilibing kung saan. Dahil sa pagkaduwag, hindi tumutol ang bayan ng San Diego. Kung sa bagay, totoo na iilan lamang ang nakaalam, wala ni isang kamag-anak ang yumao, at nasa Europa ang bugtong niyang anak. Ngunit nakarating sa Kaniyang Kataas-taasan ang lahat at dahil isang taong may pusong makatwiran ay humingi ng parusa at inilipat si Padre Damaso sa ibang mas mabuting bayan. Ito ang buong pangyayari. Ngayon, gawin ng Inyong Reberensiya ang inyong mga pagbubukod.”\nAt pagkasabi nito, lumayo siya sa pangkat.\n\n“Ikinalulungkot kong masalang, nang di sinasadya, ang isang bagay na napakaselan,” nagsisising wika ni Padre Sibyla. “Pero kung sa dulo’y may naging pakinabang sa pagpapalit ng bayan...”\n“Ano ang magiging pakinabang! At paano ang mga nawala dahil sa paglilipat... ang mga papeles...at ang mga...at ang lahat ng mga nawaglit?” nagkakandautal na sabad ni Fray Damaso na walang pagsidlan ng galit.\n\nUnti-unting bumalik ang naunang katiwasayan sa pagtitipon. Dumating ang ilan pang tao, kabilang sa kanila ang isang matandang Espanyol, pilay, may mukhang maamo at hindi nakaiinis, nakaalalay sa bisig ng isang matandang Filipina na kulot na kulot at makapal ang kolorete at nakabestidang Europeo.\n\nMalugod silang binati ng pangkat. Nakiumpok si Doktor de Espadana at ang kaniyang ginang, ang Doktora Donya Victorina, sa piling ng mga kakilala na natin. Nagkita-kita ang ilang peryodista, nagbatian ang mga negosyante, yao’t dito na hindi malaman ang gagawin.\n\n“Pero maaari ba ninyong sabihin sa akin, Senyor Laruja, kung ano ang ugali ng may bahay?” tanong ng binatang mapula ang buhok. “Hindi pa ako naipakikilala sa kanila.”\n“Ang sabi’y umalis daw. Hindi ko pa rin sila nakikita.”\n“Dito’y hindi kailangan ang pagpapakilala!” sabad ni Fray Damaso. “Isang masunuring tao si Santiago.”\n“Isang tao na hindi nakaimbento ng pulbura,” dugtong ni Laruja.\n\n“Kayo naman, Senyor de Laruja!” bulalas nang may malambing na paninisi ni Donya Victorina habang nagpapaypay. “Paanong maiimbento ng pobre ang pulbura samantalang sinasabi na naimbento ito ng mga Tsino daan-daang taon na ang nakalipas?”\n“Mga Tsino? Baliw ba kayo?” bulalas ni Fray Damaso. “Magtigil kayo! Inimbento iyon ng isang Pransiskano, isa sa aking orden, si Fray...Savalls yata ang ngalan noong siglo-siyete!”\n“Isang Pransiskano! Buweno, isang misyonero marahil sa Tsina ang Padre Savalls na iyon,” tugon ng ginang na hindi basta-basta bumibitiw sa kaniyang mga palagay.\n\n“Baka Schwartz ang ibig ninyong sabihin, senyora,” tutol ni Fray Sibyla nang hindi tumitingin sa ginang.\n\n“Ewan ko. Savalls ang sabi ni Fray Damaso. Inulit ko lamang ang sinabi niya.”\n“Siya na! Savalls o Chevas, ano ang pagkakaiba? Dahil sa isang letra’y hindi siya magiging Tsino!” bugnot na tugon ng Pransiskano.\n\n“At sa siglo katorse, hindi sa siyete,” dagdag ng Dominiko sa himig na nagwawasto upang tudyuhin wari ang kayabangan ng isa.\n\n“Buweno, isang siglong labis o isang siglong kulang, hindi pa rin magiging Dominiko!”\n“Kayo naman, huwag kayong magalit Inyong Reberensiya!” nangingiting wika ni Padre Sibyla. “Mainam na ngang inimbento niya. Sa gayon, naligtas sa gawaing iyon ang kaniyang mga kapatid.”\n“At sabi ninyo, Padre Sibyla, na sa siglo katorse iyon?” buong hilig na tanong ni Donya Victorina, “bago o pagkaraan ni Kristo?”\nSa malaking tuwa ng tinanong, pumasok ang dalawang tao sa sala.');

-- Insert Glossary Words
INSERT INTO glossary (word, definition, modern_context) VALUES 
('limatik', 'Isang uri ng linta na sumisipsip ng dugo.', 'Sa kwento, tumutukoy ito sa mga taong mapagsamantala sa iba.'),
('nag-apuhap', 'Paghahanap sa pamamagitan ng pakapa-kapa o paghahanap sa dilim.', 'Ginamit ito upang ilarawan ang paghahanap ng mga gamit para sa handaan.'),
('biton', 'Pampakintab ng sapatos (shoeshine).', 'Kailangang kintabin ang mga sapatos para sa mahalagang pagtitipon.'),
('zaguan', 'Ang maluwang na entrada o pasukan ng bahay na bato na karaniwang paradahan ng karwahe.', 'Bahagi ng arkitektura ng sinaunang bahay sa Pilipinas.'),
('porselana', 'Isang uri ng seramika na karaniwang galing sa Tsina, ginagamit sa mamahaling paso.', 'Simbolo ng karangyaan sa bahay ni Kapitan Tiago.'),
('caida', 'Ang bulwagan sa itaas ng hagdanan na nagsisilbing hintayan o tambayan.', 'Dito tinatanggap ang mga panauhin bago pumasok sa sala.'),
('linso', 'Telang lino na ginagamit sa pagpipinta.', 'Ginamit para sa mga kuwadro sa loob ng bahay.'),
('aranya', 'Mabulaklak o dekoratibong ilawan na nakasabit sa kisame (chandelier).', 'Nagbibigay ng liwanag at gilas sa sala.'),
('abaniko', 'Paypay na nakatupi, karaniwang gamit ng mga kababaihan sa panahon ng Kastila.', 'Ginagamit upang pagtakpan ang paghikab o bilang palamuti.'),
('buyo', 'Nganga (pinaghalong dahon ng ikmo, bunga, at apog).', 'Karaniwang iniaalok sa mga panauhin noon.'),
('fraile', 'Pari na kabilang sa isang relihiyosong orden (gaya ng Pransiskano o Dominiko).', 'Sila ang may malakas na impluwensya sa lipunan noon.'),
('disenteriya', 'Isang malalang sakit sa tiyan na nagdudulot ng madalas na pagdumi.', 'Binanggit ito ni Fray Damaso kaugnay ng mga silyang galing Europa.'),
('erehe', 'Isang taong sumusuway sa mga aral o dogma ng simbahan.', 'Isang mabigat na akusasyon sa panahon ng Kastila.'),
('tinola', 'Isang lutuing Pilipino na may manok, upo (o sayote), at sili.', 'Binanggit ito bilang isa sa mga pagkaing inihain sa handaan.'),
('kurwahe', 'Sasakyang hinihila ng kabayo.', 'Pangunahing transportasyon ng mga mayayaman noon.');

